import React, { useState } from 'react';
import { Project, ProjectStatus } from '../types';
import { UploadCloud, FileText, Play, CheckCircle2, ArrowRight, Loader2 } from 'lucide-react';
import { simulateProcess } from '../services/mockService';

interface ProjectDetailProps {
  project: Project;
  onAnalysisComplete: () => void;
  onViewAnalysis: () => void;
}

export const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onAnalysisComplete, onViewAnalysis }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);

  const handleStartAnalysis = async () => {
    setIsProcessing(true);
    setProgress(10);

    // Simulate steps
    await simulateProcess(1000); // OCR
    setProgress(30);
    await simulateProcess(1500); // Structure extraction
    setProgress(60);
    await simulateProcess(1500); // Rule matching
    setProgress(90);
    await simulateProcess(1000); // Report gen
    setProgress(100);

    setIsProcessing(false);
    onAnalysisComplete();
  };

  if (project.status === ProjectStatus.READY_FOR_REVIEW || project.status === ProjectStatus.COMPLETED) {
     // If already done, show a ready state
     return (
        <div className="p-8 max-w-5xl mx-auto text-center py-20">
            <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
                <CheckCircle2 size={40} />
            </div>
            <h2 className="text-3xl font-bold text-slate-900 mb-4">分析已完成</h2>
            <p className="text-slate-500 mb-8 max-w-lg mx-auto">AI 已完成对招标文件和 3 份投标文件的处理。您现在可以查看详细的对比分析报告。</p>
            <button 
                onClick={onViewAnalysis}
                className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-xl shadow-lg font-medium text-lg inline-flex items-center space-x-2 transition-transform hover:scale-105"
            >
                <span>进入评审工作区</span>
                <ArrowRight size={20} />
            </button>
        </div>
     )
  }

  return (
    <div className="p-8 max-w-5xl mx-auto space-y-8">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-slate-900">{project.title}</h1>
        <p className="text-slate-500">{project.code} • 创建于 {project.createDate}</p>
      </div>

      {/* Upload Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">

        {/* Tender Doc */}
        <div className="bg-white p-8 rounded-xl border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-slate-50 transition-all group cursor-pointer relative overflow-hidden">
          <div className="flex flex-col items-center justify-center text-center py-4 relative z-10">
            <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform shadow-sm">
              <FileText size={28} />
            </div>
            <h3 className="font-bold text-slate-900 text-lg">招标文件</h3>
            <p className="text-sm text-slate-500 mt-2 mb-6 max-w-xs">请上传 PDF 或 Word 格式的招标文件，AI 将自动提取评审标准。</p>
            {project.tenderDocName ? (
               <div className="flex items-center space-x-2 text-sm text-green-700 bg-green-50 px-4 py-2 rounded-full font-medium border border-green-100">
                  <CheckCircle2 size={16} />
                  <span>{project.tenderDocName}</span>
               </div>
            ) : (
                <button className="bg-white border border-slate-200 text-slate-700 hover:text-blue-600 hover:border-blue-200 px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm">
                  点击上传
                </button>
            )}
          </div>
        </div>

        {/* Bidder Docs */}
        <div className="bg-white p-8 rounded-xl border-2 border-dashed border-slate-300 hover:border-purple-400 hover:bg-slate-50 transition-all group cursor-pointer relative overflow-hidden">
          <div className="flex flex-col items-center justify-center text-center py-4 relative z-10">
            <div className="w-16 h-16 bg-purple-50 text-purple-600 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform shadow-sm">
              <UploadCloud size={28} />
            </div>
            <h3 className="font-bold text-slate-900 text-lg">投标文件</h3>
            <p className="text-sm text-slate-500 mt-2 mb-6 max-w-xs">批量上传供应商的投标文件。支持 PDF, Word。</p>

            {project.bidderCount > 0 ? (
               <div className="flex flex-col space-y-2 w-full max-w-xs">
                  <div className="flex items-center justify-between text-sm text-purple-700 bg-purple-50 px-4 py-2 rounded-lg border border-purple-100">
                      <span className="flex items-center"><FileText size={14} className="mr-2"/> 科技巨人...pdf</span>
                      <CheckCircle2 size={14} />
                  </div>
                  <div className="flex items-center justify-between text-sm text-purple-700 bg-purple-50 px-4 py-2 rounded-lg border border-purple-100">
                      <span className="flex items-center"><FileText size={14} className="mr-2"/> 创新服务...pdf</span>
                      <CheckCircle2 size={14} />
                  </div>
                  <div className="text-xs text-slate-400 mt-1">+ 已上传 {project.bidderCount} 个文件</div>
               </div>
            ) : (
                <button className="bg-white border border-slate-200 text-slate-700 hover:text-purple-600 hover:border-purple-200 px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm">
                  批量上传
                </button>
            )}
          </div>
        </div>
      </div>

      {/* Action Footer */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row items-center justify-between gap-4">
        <div>
           <h3 className="font-semibold text-slate-900">准备就绪</h3>
           <p className="text-sm text-slate-500">已上传 1 份招标文件和 {project.bidderCount || 0} 份投标文件。点击开始进行智能分析。</p>
        </div>

        {isProcessing ? (
           <div className="w-full md:w-64">
              <div className="flex justify-between text-xs font-medium text-slate-500 mb-1">
                 <span>AI 分析中...</span>
                 <span>{progress}%</span>
              </div>
              <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                 <div className="h-full bg-blue-600 transition-all duration-300" style={{ width: `${progress}%` }}></div>
              </div>
              <p className="text-xs text-slate-400 mt-2 text-center animate-pulse">正在提取合规性指标...</p>
           </div>
        ) : (
            <button 
                onClick={handleStartAnalysis}
                disabled={!project.tenderDocName}
                className={`px-6 py-3 rounded-lg font-medium flex items-center space-x-2 transition-all
                  ${project.tenderDocName 
                    ? 'bg-slate-900 text-white hover:bg-slate-800 shadow-md hover:shadow-lg' 
                    : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}
            >
                {isProcessing ? <Loader2 className="animate-spin" size={20} /> : <Play size={20} />}
                <span>开始智能评标</span>
            </button>
        )}
      </div>
    </div>
  );
};

